package ConditionalStatement_learn;

/**
 * 
 */
public class ElseIfCondition {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		boolean flag = true;
		int currentspeed = 10;
		if(flag) {
			currentspeed--;
			System.out.println("The speed is reduced");
		}
		else {
			System.out.println("The bike is stopped due to over speed");
		}
	}

}
